import React, { useState, createContext, useContext, useEffect, useRef, useCallback, useMemo, useReducer, Component } from 'react';

// ─── ERROR BOUNDARY ───────────────────────────────────────────────────────────
// Catches render errors in child components so the whole app doesn't go black.
class AppErrorBoundary extends Component {
  constructor(props) { super(props); this.state = { hasError: false, error: null }; }
  static getDerivedStateFromError(error) { return { hasError: true, error }; }
  componentDidCatch(error, info) { console.error('[TrailHub] Render error:', error, info); }
  render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen bg-stone-950 flex items-center justify-center p-8">
          <div className="max-w-md w-full bg-stone-900 border border-stone-800 rounded-2xl p-8 text-center">
            <div className="w-12 h-12 bg-red-500/20 rounded-full flex items-center justify-center mx-auto mb-4">
              <svg className="w-6 h-6 text-red-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>
            <h2 className="text-white font-semibold text-lg mb-2">Etwas ist schiefgelaufen</h2>
            <p className="text-stone-400 text-sm mb-6">Diese Seite konnte nicht geladen werden.</p>
            <button
              onClick={() => { this.setState({ hasError: false, error: null }); window.history.back(); }}
              className="px-6 py-2.5 bg-amber-500 text-stone-950 rounded-xl font-medium hover:bg-amber-400 transition-colors"
            >
              Zurück
            </button>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}
