// ============================================================================
// EVENTS VIEW CONTEXT - For preserving state across navigation
// ============================================================================

const EventsViewContext = createContext(null);

function useEventsView() {
  const context = useContext(EventsViewContext);
  if (!context) {
    // Return a default implementation if not wrapped (for backwards compatibility)
    return {
      savedState: null,
      saveState: () => { },
      clearState: () => { },
      hasSavedState: () => false,
    };
  }
  return context;
}

function EventsViewProvider({ children }) {
  const [savedState, setSavedState] = useState(null);

  const saveState = useCallback((state) => {
    setSavedState({
      ...state,
      timestamp: Date.now(),
    });
  }, []);

  const clearState = useCallback(() => {
    setSavedState(null);
  }, []);

  const hasSavedState = useCallback(() => {
    return savedState !== null;
  }, [savedState]);

  return (
    <EventsViewContext.Provider value={{ savedState, saveState, clearState, hasSavedState }}>
      {children}
    </EventsViewContext.Provider>
  );
}

// ============================================================================
// SHARED FILTERS CONTEXT — syncs key filters between Events ↔ Map tabs
// ============================================================================

const SharedFiltersContext = createContext(null);

function useSharedFilters() {
  return useContext(SharedFiltersContext);
}

const SHARED_FILTERS_DEFAULT = {
  searchQuery: '',
  filterCategory: 'all',       // 'all' → map shows all categories by default
  // Trail Adventures
  trailSubcategory: 'all',
  trailTime: 'all',
  trailDifficulty: 'all',
  trailPrice: 'all',
  trailDuration: 'all',
  // Rallyes
  rallyeTime: 'all',
  rallyeRegion: 'all',
  // Adventure Trips
  tripType: 'all',
  tripTime: 'all',
  // Skills Camps
  skillLevel: 'all',
  skillTime: 'all',
  // Offroad Festivals
  festivalTime: 'all',
  // Cross-category
  trailInArea: false,
  trailRadius: 200,
  userLocation: null,
  locationCity: '',
  filterCountries: [],
};

function SharedFiltersProvider({ children }) {
  const [sf, setSf] = useState(SHARED_FILTERS_DEFAULT);
  // Exact filtered event list from EventsOverview — null when no filters active
  const [sharedEvents, setSharedEvents] = useState(null);

  const setSharedFilters = useCallback((updates) => {
    setSf(prev => ({ ...prev, ...updates }));
  }, []);

  const activeFilterCount =
    (sf.searchQuery.length > 0 ? 1 : 0) +
    // Trail Adventures
    (sf.trailTime !== 'all' ? 1 : 0) +
    (sf.trailDifficulty !== 'all' ? 1 : 0) +
    (sf.trailPrice !== 'all' ? 1 : 0) +
    (sf.trailDuration !== 'all' ? 1 : 0) +
    // Rallyes
    (sf.rallyeTime !== 'all' ? 1 : 0) +
    (sf.rallyeRegion !== 'all' ? 1 : 0) +
    // Adventure Trips
    (sf.tripType !== 'all' ? 1 : 0) +
    (sf.tripTime !== 'all' ? 1 : 0) +
    // Skills Camps
    (sf.skillLevel !== 'all' ? 1 : 0) +
    (sf.skillTime !== 'all' ? 1 : 0) +
    // Offroad Festivals
    (sf.festivalTime !== 'all' ? 1 : 0) +
    // Cross-category
    (sf.trailInArea ? 1 : 0) +
    (sf.filterCountries.length > 0 ? 1 : 0);
  const hasActiveFilters = activeFilterCount > 0;

  const clearAllSharedFilters = useCallback(() => {
    setSf(SHARED_FILTERS_DEFAULT);
    setSharedEvents(null);
  }, []);

  return (
    <SharedFiltersContext.Provider value={{ sf, setSharedFilters, hasActiveFilters, activeFilterCount, clearAllSharedFilters, sharedEvents, setSharedEvents }}>
      {children}
    </SharedFiltersContext.Provider>
  );
}

