function formatMxTrackDaysShort(track, lang = 'de') {
  if (!track.openDays || track.openDays.length === 0) return '';
  const shorts = dayNamesShort[lang] || dayNamesShort.de;
  return track.openDays.map(d => shorts[d] || d).join(', ');
}

