function translateLocation(location, language) {
  if (!location) return location;
  const parts = location.split(',').map(p => p.trim());
  const translatedParts = parts.map(part => {
    const translation = countryTranslations[part];
    return translation ? translation[language] || part : part;
  });
  return translatedParts.join(', ');
}

function isThisWeekend(dateStr) {
  const eventDate = new Date(dateStr);
  const today = new Date();
  const dayOfWeek = today.getDay();
  const daysUntilSaturday = (6 - dayOfWeek + 7) % 7;
  const saturday = new Date(today);
  saturday.setDate(today.getDate() + daysUntilSaturday);
  saturday.setHours(0, 0, 0, 0);
  const sunday = new Date(saturday);
  sunday.setDate(saturday.getDate() + 1);
  sunday.setHours(23, 59, 59, 999);
  return eventDate >= saturday && eventDate <= sunday;
}

// Discipline Badge Config - Trail Adventures only
const DISCIPLINE_BADGE_CONFIG = {
  'trail': { label: 'Trail', bg: 'bg-emerald-600', text: 'text-white' },
  'enduro': { label: 'Enduro', bg: 'bg-amber-500', text: 'text-stone-900' },
  'hard-enduro': { label: 'Hard Enduro', bg: 'bg-red-600', text: 'text-white' },
};

function DisciplineBadge({ event, size = 'md' }) {
  if (event.category !== 'trail-adventures') return null;
  const config = DISCIPLINE_BADGE_CONFIG[event.subcategory];
  if (!config) return null;
  const sizeClass = size === 'sm' ? 'px-1.5 py-0.5 text-[10px]' : size === 'lg' ? 'px-3 py-1.5 text-xs' : 'px-2 py-1 text-xs';
  return <span className={`${sizeClass} ${config.bg} ${config.text} font-bold rounded-md shadow-lg`}>{config.label}</span>;
}

// ─── INITIALS AVATAR ──────────────────────────────────────────────────────────
const AVATAR_COLORS = [
  'bg-amber-600', 'bg-orange-600', 'bg-rose-600', 'bg-pink-600',
  'bg-purple-600', 'bg-indigo-600', 'bg-blue-600', 'bg-teal-600',
  'bg-emerald-600', 'bg-lime-600',
];
function getAvatarColor(name) {
  if (!name) return AVATAR_COLORS[0];
  let hash = 0;
  for (let i = 0; i < name.length; i++) hash = name.charCodeAt(i) + ((hash << 5) - hash);
  return AVATAR_COLORS[Math.abs(hash) % AVATAR_COLORS.length];
}
function InitialsAvatar({ name, avatar, size = 'md', className = '', onClick }) {
  const sizeMap = { xs: 'w-6 h-6 text-[10px]', sm: 'w-8 h-8 text-xs', md: 'w-10 h-10 text-sm', lg: 'w-12 h-12 text-base', xl: 'w-16 h-16 text-xl', '2xl': 'w-20 h-20 text-2xl', '3xl': 'w-24 h-24 text-3xl' };
  const initials = name ? name.trim().split(/\s+/).map(w => w[0]).slice(0, 2).join('').toUpperCase() : '?';
  if (avatar) return <img src={avatar} alt={name} className={`${sizeMap[size] || sizeMap.md} rounded-full object-cover ${className}`} onClick={onClick} />;
  return <div className={`${sizeMap[size] || sizeMap.md} rounded-full flex items-center justify-center font-bold text-white flex-shrink-0 ${getAvatarColor(name)} ${className}`} onClick={onClick}>{initials}</div>;
}

// ─── BIO RENDERER (linkify + preserve newlines) ───────────────────────────────
function renderBio(text) {
  if (!text) return null;
  const URL_RE = /https?:\/\/[^\s<>"]+/g;
  const MENTION_RE = /@[\w.]+/g;
  const segments = [];
  let last = 0;
  const matches = [];
  let m;
  const combined = new RegExp(`${URL_RE.source}|${MENTION_RE.source}`, 'g');
  while ((m = combined.exec(text)) !== null) matches.push({ start: m.index, end: m.index + m[0].length, raw: m[0] });
  matches.forEach(({ start, end, raw }) => {
    if (start > last) segments.push({ type: 'text', value: text.slice(last, start) });
    if (raw.startsWith('http')) segments.push({ type: 'url', value: raw });
    else segments.push({ type: 'mention', value: raw });
    last = end;
  });
  if (last < text.length) segments.push({ type: 'text', value: text.slice(last) });
  return segments.map((seg, i) => {
    if (seg.type === 'url') return <a key={i} href={seg.value} target="_blank" rel="noopener noreferrer" className="text-amber-400 hover:text-amber-300 underline break-all" onClick={e => e.stopPropagation()}>{seg.value}</a>;
    if (seg.type === 'mention') return <span key={i} className="text-amber-400">{seg.value}</span>;
    return seg.value.split('\n').map((line, j, arr) => j < arr.length - 1 ? <span key={`${i}-${j}`}>{line}<br /></span> : <span key={`${i}-${j}`}>{line}</span>);
  });
}

