// Event Detail Page
function EventDetailPage({ event: eventProp, onBack, isLoggedIn, onViewEvent, setCurrentView, onViewFriend, onCategoryClick }) {
  const { t, language } = useTranslation();
  const { isRegistered, isFavorite, toggleRegistration, toggleFavorite, friendsPerEvent, eventDateSelections, saveEventDateSelection } = useUserState();

  // Enrich event data on mount: if coordinates or AI summaries are missing (e.g. when
  // navigating from FeaturedEvents with a partial object), fetch the full record from Supabase.
  const [event, setEvent] = useState(eventProp);
  useEffect(() => { setEvent(eventProp); }, [eventProp.id]); // reset when event changes

  const registeredFriends = friendsPerEvent.get(event.id) ?? [];
  const [selectedFriend, setSelectedFriend] = useState(null);
  const [showOrganizerPopup, setShowOrganizerPopup] = useState(false);
  const [shareStatus, setShareStatus] = useState(null); // null, 'copied', 'shared'
  const [pendingRegId, setPendingRegId] = useState(null);

  const handleRegClick = () => {
    if (isRegistered(event.id)) { toggleRegistration(event.id); return; }
    if (localStorage.getItem(REG_POPUP_KEY) === 'true') { toggleRegistration(event.id); return; }
    setPendingRegId(event.id);
  };

  // ── Multi-date selector state ──────────────────────────────────────────────
  // liveEventDates: source of truth for event_dates; refreshed from Supabase on mount.
  // selectedDateIdx: which date in the list is currently active.
  // Both useState calls must come before any derived const that reads them.
  const [liveEventDates, setLiveEventDates] = useState(event.eventDates || null);
  const [selectedDateIdx, setSelectedDateIdx] = useState(() => {
    const dates = event.eventDates;
    if (!dates || dates.length === 0) return 0;
    var now = new Date();
    var fi = dates.findIndex(function(d) { return new Date(d.start_date || d.start) >= now; });
    return fi >= 0 ? fi : dates.length - 1;
  });

  // Ref: prevents the "first-future date" default from overriding a user-saved selection.
  const savedIdxAppliedRef = useRef(false);

  // On mount: fetch fresh data from Supabase.
  // - Always refreshes event_dates (multi-date events need up-to-date entries)
  // - Enriches coordinates + AI summaries if missing (e.g. navigation from FeaturedEvents)
  useEffect(() => {
    const fetchFreshData = async () => {
      try {
        const freshData = await fetchEventById(event.id);

        // Enrich missing fields from the full DB record
        const needsCoords = !event.coordinates?.lat;
        const needsAI = !event.aiSummaryDe && !event.aiSummaryEn && !event.aiSummaryFr && !event.aiSummaryNl;

        if (needsCoords || needsAI || Array.isArray(freshData.event_dates)) {
          setEvent(prev => ({
            ...prev,
            ...(needsCoords && freshData.coordinates ? {
              coordinates: (() => {
                const c = freshData.coordinates;
                if (!c) return null;
                if (c.lat != null && c.lng != null) return c;
                if (c.latitude != null && c.longitude != null) return { lat: c.latitude, lng: c.longitude };
                return null;
              })(),
            } : {}),
            ...(needsAI ? {
              aiSummaryDe:        freshData.ai_summary_de         ?? null,
              aiSummaryEn:        freshData.ai_summary_en         ?? null,
              aiSummaryFr:        freshData.ai_summary_fr         ?? null,
              aiSummaryNl:        freshData.ai_summary_nl         ?? null,
              aiSummaryUpdatedAt: freshData.ai_summary_updated_at ?? null,
            } : {}),
          }));
        }

        if (Array.isArray(freshData.event_dates) && freshData.event_dates.length > 0) {
          setLiveEventDates(freshData.event_dates);
          // Only set default idx if the user's saved selection hasn't been applied yet.
          if (!savedIdxAppliedRef.current) {
            var now2 = new Date();
            var fi2 = freshData.event_dates.findIndex(function(d) {
              return new Date(d.start_date || d.start) >= now2;
            });
            setSelectedDateIdx(fi2 >= 0 ? fi2 : freshData.event_dates.length - 1);
          }
        }
      } catch (err) {
        console.warn('[TrailHub] fetchEventById failed:', err);
      }
    };
    fetchFreshData();
  }, [event.id]); // eslint-disable-line

  // Apply the user's saved date selection once both liveEventDates and eventDateSelections load.
  useEffect(() => {
    if (savedIdxAppliedRef.current) return;
    const savedIdx = eventDateSelections[String(event.id)];
    if (savedIdx === undefined || savedIdx === null) return;
    if (!liveEventDates || !liveEventDates[savedIdx]) return;
    savedIdxAppliedRef.current = true;
    setSelectedDateIdx(savedIdx);
  }, [eventDateSelections, liveEventDates]); // eslint-disable-line

  // hasAnyDates – 1+ entries → use event_dates date in meta box display
  const hasAnyDates = Array.isArray(liveEventDates) && liveEventDates.length >= 1;
  const _selectedEntry = hasAnyDates ? (liveEventDates[selectedDateIdx] || liveEventDates[0] || null) : null;
  const displayStartDate = _selectedEntry ? (_selectedEntry.start_date || _selectedEntry.start || event.startDate) : event.startDate;
  const displayEndDate   = _selectedEntry ? (_selectedEntry.end_date   || _selectedEntry.end   || event.endDate || null) : (event.endDate || null);

  const localeMap = { de: 'de-DE', en: 'en-US', fr: 'fr-FR', nl: 'nl-NL' };
  const translatedLocationForShare = translateLocation(event.location, language);

  // Share handler
  const handleShare = async () => {
    const shareUrl = `${window.location.origin}/event/${event.id}`;
    const shareData = {
      title: event.name,
      text: `${event.name} - ${translatedLocationForShare}`,
      url: shareUrl,
    };

    try {
      if (navigator.share) {
        await navigator.share(shareData);
        setShareStatus('shared');
      } else {
        await navigator.clipboard.writeText(shareUrl);
        setShareStatus('copied');
      }
      setTimeout(() => setShareStatus(null), 2000);
    } catch (err) {
      if (err.name !== 'AbortError') {
        try {
          await navigator.clipboard.writeText(shareUrl);
          setShareStatus('copied');
          setTimeout(() => setShareStatus(null), 2000);
        } catch {
          // Fallback failed silently
        }
      }
    }
  };

  // Check if this is a past event and determine its status
  const eventPastStatus = getPastEventStatus(event.endDate);
  const isPastEvent = eventPastStatus !== 'future';
  const isArchivedEvent = eventPastStatus === 'archived';
  const isExpiredEvent = eventPastStatus === 'expired';

  // Redirect back if event is expired (>3 years old)
  useEffect(() => {
    if (isExpiredEvent && onBack) {
      onBack();
    }
  }, [isExpiredEvent, onBack]);

  // Don't render if event is expired
  if (isExpiredEvent) {
    return null;
  }

  // Translated location
  const translatedLocation = translateLocation(event.location, language);
  const locationCity = translatedLocation.split(',')[0];
  const locationCountry = translatedLocation.split(',').slice(1).join(',').trim();

  // Get organizer data – prefer the snapshot joined with the event (includes logo_bg_color),
  // fall back to the module-level organizers map, then to the mock placeholder.
  const organizer = event.organizerSnap || organizers[event.organizerId] || organizers['enduro-events'];

  // Get all events from this organizer
  const organizerEvents = mockEvents.filter(e => e.organizerId === event.organizerId && e.id !== event.id);

  // More similar events for marquee - only future events
  const similarEvents = mockEvents
    .filter(e => e.category === event.category && e.id !== event.id && new Date(e.startDate) >= new Date())
    .slice(0, 8);
  const duplicatedSimilar = [...similarEvents, ...similarEvents];

  // Language-specific AI summary — reads directly from DB fields, NULL = nothing to show
  const aiSummary = { de: event.aiSummaryDe, en: event.aiSummaryEn, fr: event.aiSummaryFr, nl: event.aiSummaryNl }[language] ?? null;

  const categoryLabels = {
    'trail-adventures': t('trailAdventures'),
    'rallyes': t('rallyes'),
    'adventure-trips': t('adventureTrips'),
    'skills-camps': t('skillsCamps'),
    'offroad-festivals': t('offroadFestivals'),
  };

  // Organizer Popup
  const OrganizerPopup = () => (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4" onClick={() => setShowOrganizerPopup(false)}>
      <div className="bg-stone-900 rounded-2xl border border-stone-700 p-6 max-w-lg w-full shadow-2xl max-h-[80vh] overflow-hidden flex flex-col" onClick={e => e.stopPropagation()}>
        {/* Header */}
        <div className="flex items-center gap-4 mb-6">
          <div
            className="organizer-logo-bg w-16 h-16 rounded-xl border-2 border-amber-500/30 flex-shrink-0 flex items-center justify-center"
            style={{ '--org-logo-bg': organizer.logoBgColor || 'transparent' }}
          >
            <img
              src={organizer.logo}
              alt={organizer.name}
              className="w-full h-full object-contain p-1"
              onError={(e) => { e.target.style.display='none'; e.target.nextSibling?.style && (e.target.nextSibling.style.display='flex'); }}
            />
            <div style={{display:'none'}} className="w-full h-full flex items-center justify-center text-amber-500 font-bold text-xl">
              {organizer.name?.[0] ?? '?'}
            </div>
          </div>
          <div className="flex-1">
            <div className="flex items-center gap-2">
              <h3 className="text-xl font-semibold text-white">{organizer.name}</h3>
              {organizer.verified && (
                <svg className="w-5 h-5 text-amber-500" fill="currentColor" viewBox="0 0 20 20">
                  <path fillRule="evenodd" d="M6.267 3.455a3.066 3.066 0 001.745-.723 3.066 3.066 0 013.976 0 3.066 3.066 0 001.745.723 3.066 3.066 0 012.812 2.812c.051.643.304 1.254.723 1.745a3.066 3.066 0 010 3.976 3.066 3.066 0 00-.723 1.745 3.066 3.066 0 01-2.812 2.812 3.066 3.066 0 00-1.745.723 3.066 3.066 0 01-3.976 0 3.066 3.066 0 00-1.745-.723 3.066 3.066 0 01-2.812-2.812 3.066 3.066 0 00-.723-1.745 3.066 3.066 0 010-3.976 3.066 3.066 0 00.723-1.745 3.066 3.066 0 012.812-2.812zm7.44 5.252a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                </svg>
              )}
            </div>
            <p className="text-stone-400 text-sm">{organizer.description}</p>
          </div>
        </div>

        {/* Events List */}
        <div className="flex-1 overflow-y-auto">
          <p className="text-xs uppercase tracking-wider text-stone-500 mb-3">
            {t('allEventsFromOrganizer')} ({organizerEvents.length + 1})
          </p>

          {/* Current Event */}
          <div className="flex items-center gap-3 bg-amber-500/10 border border-amber-500/20 rounded-lg p-3 mb-2">
            <img src={event.image} alt={event.name} className="w-16 h-12 rounded object-cover" />
            <div className="flex-1 min-w-0">
              <p className="text-amber-400 text-sm font-medium truncate">{event.name}</p>
              <p className="text-stone-500 text-xs">{formatDate(event.startDate)} • {event.location.split(',')[0]}</p>
            </div>
            <span className="text-xs text-amber-500 bg-amber-500/10 px-2 py-1 rounded">{t('currentEvent')}</span>
          </div>

          {/* Other Events */}
          <div className="space-y-2">
            {organizerEvents.map(orgEvent => (
              <div
                key={orgEvent.id}
                className="flex items-center gap-3 bg-stone-800/50 rounded-lg p-3 hover:bg-stone-800 transition-colors cursor-pointer"
                onClick={() => { setShowOrganizerPopup(false); onViewEvent(orgEvent); }}
              >
                <img src={orgEvent.image} alt={orgEvent.name} className="w-16 h-12 rounded object-cover" />
                <div className="flex-1 min-w-0">
                  <p className="text-white text-sm font-medium truncate">{orgEvent.name}</p>
                  <p className="text-stone-500 text-xs">{formatDate(orgEvent.startDate)} • {orgEvent.location.split(',')[0]}</p>
                </div>
                <svg className="w-5 h-5 text-stone-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                </svg>
              </div>
            ))}
          </div>

          {organizerEvents.length === 0 && (
            <p className="text-stone-500 text-sm text-center py-4">{t('noResults')}</p>
          )}
        </div>

        {/* Footer */}
        <div className="mt-6 pt-4 border-t border-stone-800">
          <button
            onClick={() => setShowOrganizerPopup(false)}
            className="w-full py-3 bg-stone-800 text-stone-300 rounded-xl text-sm font-medium hover:bg-stone-700 transition-colors"
          >
            {t('close')}
          </button>
        </div>
      </div>
    </div>
  );

  // Friend Popup for detail page
  const FriendDetailPopup = ({ friend, onClose, onViewFriend }) => {
    const [nudged, setNudged] = useState(false);
    const friendEvents = [];

    const handleNudge = () => {
      setNudged(true);
      setTimeout(() => setNudged(false), 2000);
    };

    return (
      <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4" onClick={onClose}>
        <div className="bg-stone-900 rounded-2xl border border-stone-700 p-6 max-w-md w-full shadow-2xl" onClick={e => e.stopPropagation()}>
          <div className="flex items-center gap-4 mb-6">
            <InitialsAvatar name={friend.name} avatar={friend.avatar} size="xl" className="border-2 border-amber-500/30 cursor-pointer" onClick={() => { onClose(); onViewFriend && onViewFriend(friend); }} />
            <div>
              <h3 className="text-xl font-semibold text-white">{friend.name}</h3>
              <p className="text-stone-400 text-sm">{friendEvents.length} {t('eventsPlanned')}</p>
            </div>
          </div>

          {friendEvents.length > 0 && (
            <div className="mb-6">
              <p className="text-xs uppercase tracking-wider text-stone-500 mb-3">{t('registeredAt')}</p>
              <div className="space-y-2 max-h-48 overflow-y-auto">
                {friendEvents.map(fe => (
                  <div key={fe.id} className="flex items-center gap-3 bg-stone-800/50 rounded-lg p-2 hover:bg-stone-800 transition-colors cursor-pointer" onClick={() => { onClose(); onViewEvent(fe); }}>
                    <img src={fe.image} alt={fe.name} className="w-12 h-8 rounded object-cover" />
                    <div className="flex-1 min-w-0">
                      <p className="text-white text-sm font-medium truncate">{fe.name}</p>
                      <p className="text-stone-500 text-xs">{formatDate(fe.startDate)}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          <div className="flex gap-3">
            <button
              onClick={handleNudge}
              className={`flex-1 py-2.5 rounded-xl text-sm font-medium transition-all ${nudged ? 'bg-emerald-500/20 text-emerald-400' : 'bg-stone-800 text-stone-300 hover:bg-stone-700'
                }`}
            >
              {nudged ? `✓ ${t('nudged')}` : `👋 ${t('nudge')}`}
            </button>
            <button
              onClick={() => { onClose(); onViewFriend && onViewFriend(friend); }}
              className="flex-1 py-2.5 bg-amber-500/20 text-amber-400 rounded-xl text-sm font-medium hover:bg-amber-500/30 transition-colors"
            >
              {t('viewProfile')}
            </button>
          </div>
        </div>
      </div>
    );
  };

  // Sticky back button visibility on scroll
  const heroRef = useRef(null);
  const [showStickyNav, setShowStickyNav] = useState(false);

  // Detail map ref and initialization
  const detailMapContainerRef = useRef(null);
  const detailMapInstanceRef = useRef(null);

  useEffect(() => {
    if (!event?.coordinates || !detailMapContainerRef.current) return;
    if (detailMapInstanceRef.current) return; // already initialized

    mapboxgl.accessToken = import.meta.env.VITE_MAPBOX_TOKEN || '';

    const map = new mapboxgl.Map({
      container: detailMapContainerRef.current,
      style: 'mapbox://styles/mapbox/dark-v11',
      center: [event.coordinates.lng, event.coordinates.lat],
      zoom: 12,
      interactive: true,
      attributionControl: false,
      preserveDrawingBuffer: true, // required for iOS WebView (Capacitor)
      fadeDuration: 0,             // smoother in WebView
    });

    map.addControl(new mapboxgl.NavigationControl({ showCompass: false }), 'top-right');

    // Add single marker
    const markerEl = document.createElement('div');
    markerEl.style.cssText = 'width:24px;height:24px;background:#f59e0b;border:3px solid #fff;border-radius:50%;box-shadow:0 2px 8px rgba(0,0,0,0.4);cursor:pointer;';
    new mapboxgl.Marker({ element: markerEl })
      .setLngLat([event.coordinates.lng, event.coordinates.lat])
      .addTo(map);

    detailMapInstanceRef.current = map;

    return () => {
      map.remove();
      detailMapInstanceRef.current = null;
    };
  }, [event?.coordinates?.lat, event?.coordinates?.lng]);

  useEffect(() => {
    const hero = heroRef.current;
    if (!hero) return;
    const observer = new IntersectionObserver(
      ([entry]) => setShowStickyNav(!entry.isIntersecting),
      { threshold: 0, rootMargin: '-64px 0px 0px 0px' }
    );
    observer.observe(hero);
    return () => observer.disconnect();
  }, []);

  return (
    <div className="min-h-screen bg-stone-950">
      {/* Sticky back + tags bar - visible when hero scrolls out */}
      <div className={`sticky top-0 z-40 transition-all duration-200 ${showStickyNav ? 'translate-y-0 opacity-100' : '-translate-y-full opacity-0 pointer-events-none'}`}>
        <div className="bg-stone-950/95 backdrop-blur-md border-b border-stone-800/50 px-4 sm:px-8 py-3">
          <div className="max-w-7xl mx-auto flex items-center gap-3 flex-wrap">
            <button
              onClick={onBack}
              className="flex items-center gap-2 px-4 py-2 bg-stone-800 rounded-full text-white text-sm hover:bg-stone-700 transition-colors"
            >
              <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
              </svg>
              {t('back')}
            </button>
            <DisciplineBadge event={event} />
            {event.mxType === 'mx-track' && (
              <span className="px-2 py-1 bg-amber-500/90 text-stone-900 text-xs font-bold rounded-md">{t('mxTrack')}</span>
            )}
            <span className="px-2 py-1 bg-stone-800/80 text-amber-400 text-xs font-medium rounded-md">
              {categoryLabels[event.category]}
            </span>
            {event.festivalType && (() => {
              const festivalLabels = {
                'Community-Treffen': t('communityMeet'), 'Hersteller-Event': t('manufacturerEvent'),
                'Demo-/Test-Event': t('demoEvent'), 'Rennen integriert': t('raceIntegrated'),
                'Messe/Expo': t('expoFair'), 'Adventure-Festival': t('adventureFestival'),
                'Hard-Enduro-Festival': t('hardEnduroFestival'),
              };
              return <span className="px-2 py-1 bg-purple-500/20 text-purple-300 text-[10px] font-medium rounded-md">{festivalLabels[event.festivalType] || event.festivalType}</span>;
            })()}
            <span className="text-white text-sm font-medium ml-auto hidden sm:block truncate max-w-[300px]">{event.name}</span>
          </div>
        </div>
      </div>

      {/* Hero - Like an expanded card */}
      <div ref={heroRef} className="relative h-[60vh] min-h-[400px] overflow-hidden" style={{ borderRadius: '0 0 2rem 2rem' }}>
        <img src={event.image} alt={event.name} className={`w-full h-full object-cover ${isPastEvent ? 'grayscale' : ''}`} />
        <div className="absolute inset-0 bg-gradient-to-t from-stone-950 via-stone-950/60 to-transparent"></div>
        <div className="absolute inset-0 bg-gradient-to-r from-stone-950/40 to-transparent"></div>
        {isPastEvent && <div className="absolute inset-0 bg-stone-950/30"></div>}

        {/* Back button - always visible */}
        <button
          onClick={onBack}
          className="absolute top-6 left-4 sm:left-8 z-10 flex items-center gap-2 px-4 py-2 bg-stone-900/80 backdrop-blur-sm rounded-full text-white text-sm hover:bg-stone-800 transition-colors"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
          {t('back')}
        </button>

        {/* Past Event Banner - inline within hero */}
        {isPastEvent && (
          <div className={`absolute top-6 left-1/2 -translate-x-1/2 z-10 px-4 py-2 rounded-full ${isArchivedEvent
            ? 'bg-stone-800/90 backdrop-blur-sm border border-stone-700'
            : 'bg-stone-900/90 backdrop-blur-sm border border-stone-800'
            }`}>
            <div className="flex items-center gap-2">
              <svg className="w-4 h-4 text-stone-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              <span className={`text-sm font-medium ${isArchivedEvent ? 'text-stone-500' : 'text-stone-400'}`}>
                {isArchivedEvent ? t('eventArchived') : (t('eventEnded') || 'Event beendet')}
              </span>
            </div>
          </div>
        )}

        {/* Badges */}
        <div className="absolute top-6 left-4 sm:left-8 mt-12 flex items-center gap-2">
          <DisciplineBadge event={event} size="lg" />
          {/* MX-Track badge */}
          {event.mxType === 'mx-track' && (
            <span className="px-3 py-1.5 bg-amber-500/90 text-stone-900 text-xs font-bold rounded-lg shadow-lg">{t('mxTrack')}</span>
          )}
          {event.isNew && (
            <span className="px-3 py-1.5 bg-emerald-500 text-white text-xs font-bold rounded-lg shadow-lg">{t('new')}</span>
          )}
          <span className="px-3 py-1.5 bg-stone-800/80 backdrop-blur-sm text-amber-400 text-xs font-medium rounded-lg">
            {categoryLabels[event.category]}
          </span>
          {/* First-Timer Friendly - NOT shown for MX track events */}
          {event.beginnerFriendly && event.mxType !== 'mx-track' && (
            <span className="px-3 py-1.5 bg-blue-500/90 text-white text-xs font-medium rounded-lg shadow-lg">{t('firstTimerFriendly')}</span>
          )}
        </div>

        {/* Action buttons (top-right) */}
        <div className="absolute top-6 right-4 sm:right-8 flex items-center gap-3">
          {/* Share button */}
          <button
            onClick={handleShare}
            className="w-12 h-12 bg-stone-900/80 backdrop-blur-sm rounded-full flex items-center justify-center hover:bg-stone-800 transition-colors"
            aria-label={t('share') || 'Share'}
          >
            {shareStatus === 'copied' ? (
              <svg className="w-6 h-6 text-emerald-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
              </svg>
            ) : (
              <svg className="w-6 h-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" />
              </svg>
            )}
          </button>

          {/* Favorite button */}
          <button
            onClick={() => toggleFavorite(event.id)}
            className="w-12 h-12 bg-stone-900/80 backdrop-blur-sm rounded-full flex items-center justify-center hover:bg-stone-800 transition-colors"
            aria-label={isFavorite(event.id) ? t('removeFromFavorites') || 'Remove from favorites' : t('addToFavorites') || 'Add to favorites'}
          >
            <svg className={`w-6 h-6 transition-colors ${isFavorite(event.id) ? 'text-red-500 fill-red-500' : 'text-white'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
            </svg>
          </button>
        </div>

        {/* Title area */}
        <div className="absolute bottom-0 left-0 right-0 p-6 sm:p-10">
          <div className="max-w-7xl mx-auto">
            {event.difficulty && <div className="mb-3"><DifficultyIcon level={event.difficulty} /></div>}
            <h1 className="text-3xl sm:text-4xl lg:text-5xl font-bold text-white mb-2 leading-tight">{event.name}</h1>

            {/* Registration Toggle */}
            {isLoggedIn && (
              <button
                onClick={handleRegClick}
                aria-label={isRegistered(event.id) ? 'Vom Event abmelden' : 'Zum Event anmelden'}
                className={`flex items-center gap-2 px-4 py-2 rounded-full font-semibold text-sm text-white shadow-md transition-all duration-300 ease-in-out mb-4 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-transparent
                  ${isRegistered(event.id)
                    ? 'bg-gradient-to-r from-[#4CAF50] to-[#45A049] shadow-green-900/40 hover:brightness-110 hover:-translate-y-0.5 hover:shadow-lg focus:ring-green-500'
                    : 'bg-gradient-to-r from-[#FF9500] to-[#FF6B00] shadow-orange-900/40 hover:brightness-110 hover:-translate-y-0.5 hover:shadow-lg focus:ring-orange-500'
                  }`}
              >
                {isRegistered(event.id) ? (
                  <svg className="w-4 h-4 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20" aria-hidden="true">
                    <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                  </svg>
                ) : (
                  <svg className="w-4 h-4 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5} aria-hidden="true">
                    <circle cx="12" cy="12" r="10" />
                  </svg>
                )}
                <span>{t('registered')}</span>
              </button>
            )}
            {pendingRegId !== null && (
              <RegistrationConfirmPopup
                onConfirm={(dontShow) => {
                  if (dontShow) localStorage.setItem(REG_POPUP_KEY, 'true');
                  toggleRegistration(pendingRegId);
                  setPendingRegId(null);
                }}
                onCancel={() => setPendingRegId(null)}
              />
            )}

            <div className="flex flex-wrap items-center gap-4 text-stone-300">
              <div className="flex items-center gap-2">
                <svg className="w-5 h-5 text-stone-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  {event.mxType === 'mx-track' ? (
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                  ) : (
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
                  )}
                </svg>
                <span>{event.mxType === 'mx-track'
                  ? `${event.seasonStart || ''} – ${event.seasonEnd || ''} • ${formatMxTrackDaysShort(event, language)}`
                  : event.isFlexibleDate
                    ? t('flexibleDateLabel')
                    : formatDateRange(event.startDate, event.endDate)}</span>
              </div>
              <div className="flex items-center gap-2">
                <svg className="w-5 h-5 text-stone-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                </svg>
                <span>{translatedLocation}</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Two Panel Content Section */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="flex flex-col lg:flex-row gap-6">

          {/* Left Panel - 60% (KI Summary — only rendered when DB field is set for current language) */}
          <div className="lg:w-[60%] bg-stone-900/50 border border-stone-800/10 rounded-2xl p-6 lg:p-8">
            {aiSummary && (
              <>
                <div className="flex items-start gap-3 mb-4">
                  <div className="w-8 h-8 bg-amber-500/15 rounded-lg flex items-center justify-center flex-shrink-0 mt-0.5">
                    <svg className="w-4 h-4 text-amber-500/80" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                    </svg>
                  </div>
                  <p className="text-[11px] uppercase tracking-wider text-amber-500/60 font-medium">{t('aiSummary')}</p>
                </div>
                <p className="text-stone-300 leading-relaxed whitespace-pre-line">{aiSummary}</p>
                {event.aiSummaryUpdatedAt && (
                  <p className="text-[10px] text-stone-600 mt-2 italic">
                    {language === 'de' ? 'Aktualisiert' : language === 'fr' ? 'Mis à jour' : language === 'nl' ? 'Bijgewerkt' : 'Updated'}: {new Date(event.aiSummaryUpdatedAt).toLocaleDateString()}
                  </p>
                )}
              </>
            )}

            {/* Friends Section - integrated into left panel */}
            {registeredFriends.length > 0 && (
              <div className="mt-8 pt-6 border-t border-stone-800/30">
                <p className="text-[11px] uppercase tracking-wider text-purple-400/60 font-medium mb-4 flex items-center gap-2">
                  <span>👥</span> {t('friendsAtEvent')}
                </p>
                <div className="flex items-center gap-3">
                  {/* Stacked avatars with overlap */}
                  <div className="flex -space-x-3">
                    {registeredFriends.slice(0, 4).map((friend) => (
                      <InitialsAvatar key={friend.id} name={friend.name} avatar={friend.avatar} size="lg" className="border-3 border-stone-900 cursor-pointer hover:scale-110 hover:z-10 transition-transform relative" onClick={() => setSelectedFriend(friend)} />
                    ))}
                  </div>
                  <div className="text-stone-400 text-sm">
                    {registeredFriends.map(f => f.name).join(', ')}
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Right Panel - 40% (Meta Box) */}
          <div className="lg:w-[40%] bg-stone-900/50 border border-stone-800/10 rounded-2xl p-6 lg:p-8 space-y-5">

            {/* Price - prominent like on cards */}
            <div className="pb-5 border-b border-stone-800/30">
              <p className="text-3xl font-bold text-amber-400">{event.isFree ? t('freeLabel') : event.price}</p>
              {!event.isFree && <p className="text-stone-600 text-xs mt-1">{t('perPerson')}</p>}
            </div>

            {/* Date / Opening Hours */}
            {event.mxType === 'mx-track' ? (
              <>
                {/* Öffnungszeiten Section for MX Tracks */}
                <div className="py-2">
                  <p className="text-[11px] uppercase tracking-wider text-amber-500/60 font-medium mb-3 flex items-center gap-2">
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                    {language === 'de' ? 'Öffnungszeiten' : language === 'fr' ? 'Horaires' : language === 'nl' ? 'Openingstijden' : 'Opening Hours'}
                  </p>

                  {/* Season */}
                  {event.seasonStart && event.seasonEnd && (
                    <div className="flex items-center gap-3 mb-3">
                      <div className="w-10 h-10 bg-amber-500/10 rounded-lg flex items-center justify-center">
                        <svg className="w-5 h-5 text-amber-500/70" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
                        </svg>
                      </div>
                      <div>
                        <p className="text-white font-medium">{event.seasonStart} – {event.seasonEnd}</p>
                        <p className="text-stone-500 text-sm">{language === 'de' ? 'Saison' : 'Season'}</p>
                      </div>
                    </div>
                  )}

                  {/* Weekly Schedule */}
                  {event.openDays && event.openDays.length > 0 && (
                    <div className="space-y-2 ml-[52px]">
                      {event.openDays.map(day => {
                        const names = dayNames[language] || dayNames.de;
                        const hours = event.openingHours?.[day] || '';
                        return (
                          <div key={day} className="flex items-center justify-between text-sm">
                            <span className="text-stone-300 font-medium">{names[day] || day}</span>
                            <span className="text-stone-400">{hours.replace('-', ' – ')} {language === 'de' ? 'Uhr' : ''}</span>
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>

                {/* Track-Infos label */}
                <div className="flex items-center gap-3 py-2 border-t border-stone-800/30 pt-4">
                  <div className="w-10 h-10 bg-stone-800/60 rounded-lg flex items-center justify-center">
                    <svg className="w-5 h-5 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                  </div>
                  <div>
                    <p className="text-white font-medium">Track-Infos</p>
                    <p className="text-stone-500 text-sm">{event.priceInfo || event.price}</p>
                  </div>
                </div>
              </>
            ) : (
              <div className="flex items-center gap-3 py-2">
                <div className="w-10 h-10 bg-stone-800/60 rounded-lg flex items-center justify-center">
                  <svg className="w-5 h-5 text-stone-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
                  </svg>
                </div>
                <div>
                  {event.isFlexibleDate ? (
                    <>
                      <p className="text-amber-400 font-medium">{t('flexibleDateLabel')}</p>
                      {event.flexibleDateInfo && (
                        <p className="text-stone-500 text-sm">{event.flexibleDateInfo}</p>
                      )}
                    </>
                  ) : (
                    <>
                      <p className="text-white font-medium">{formatDate(displayStartDate)}</p>
                      <p className="text-stone-500 text-sm">{calculateDuration(displayStartDate, displayEndDate, t)}</p>
                    </>
                  )}
                </div>
              </div>
            )}

            {/* Location */}
            <div className="flex items-center gap-3 py-2">
              <div className="w-10 h-10 bg-stone-800/60 rounded-lg flex items-center justify-center">
                <svg className="w-5 h-5 text-stone-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                </svg>
              </div>
              <div>
                <p className="text-white font-medium">{locationCity}</p>
                <p className="text-stone-500 text-sm">{locationCountry}</p>
              </div>
            </div>

            {/* Group Size - Skills-Camps only */}
            {event.category === 'skills-camps' && event.groupSize != null && (
              <div className="flex items-center gap-3 py-2">
                <div className="w-10 h-10 bg-stone-800/60 rounded-lg flex items-center justify-center">
                  <svg className="w-5 h-5 text-stone-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" />
                  </svg>
                </div>
                <div>
                  <p className="text-white font-medium">{`Max. ${event.groupSize} ${language === 'de' ? 'Teilnehmer' : language === 'fr' ? 'Participants' : language === 'nl' ? 'Deelnemers' : 'Participants'}`}</p>
                  <p className="text-stone-500 text-sm">{language === 'de' ? 'Gruppengröße' : language === 'fr' ? 'Taille du groupe' : language === 'nl' ? 'Groepsgrootte' : 'Group size'}</p>
                </div>
              </div>
            )}

            {/* Organizer - Clickable */}
            <div
              className="flex items-center gap-3 py-2 border-t border-stone-800/30 pt-5 cursor-pointer hover:bg-stone-800/30 -mx-2 px-2 rounded-lg transition-colors"
              onClick={() => setShowOrganizerPopup(true)}
            >
              <div
                className="organizer-logo-bg w-10 h-10 rounded-full border-2 border-amber-500/30 flex-shrink-0 flex items-center justify-center"
                style={{ '--org-logo-bg': organizer.logoBgColor || 'transparent' }}
              >
                <img
                  src={organizer.logo}
                  alt={organizer.name}
                  className="w-full h-full object-contain p-0.5"
                  onError={(e) => { e.target.style.display='none'; e.target.nextSibling?.style && (e.target.nextSibling.style.display='flex'); }}
                />
                <div style={{display:'none'}} className="w-full h-full flex items-center justify-center text-amber-500 font-bold text-sm">
                  {organizer.name?.[0] ?? '?'}
                </div>
              </div>
              <div className="flex-1">
                <div className="flex items-center gap-1.5">
                  <p className="text-white font-medium text-sm">{organizer.name}</p>
                  {organizer.verified && (
                    <svg className="w-4 h-4 text-amber-500" fill="currentColor" viewBox="0 0 20 20">
                      <path fillRule="evenodd" d="M6.267 3.455a3.066 3.066 0 001.745-.723 3.066 3.066 0 013.976 0 3.066 3.066 0 001.745.723 3.066 3.066 0 012.812 2.812c.051.643.304 1.254.723 1.745a3.066 3.066 0 010 3.976 3.066 3.066 0 00-.723 1.745 3.066 3.066 0 01-2.812 2.812 3.066 3.066 0 00-1.745.723 3.066 3.066 0 01-3.976 0 3.066 3.066 0 00-1.745-.723 3.066 3.066 0 01-2.812-2.812 3.066 3.066 0 00-.723-1.745 3.066 3.066 0 010-3.976 3.066 3.066 0 00.723-1.745 3.066 3.066 0 012.812-2.812zm7.44 5.252a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                    </svg>
                  )}
                </div>
                <p className="text-stone-600 text-xs">{t('verifiedOrganizer')}</p>
              </div>
              <svg className="w-5 h-5 text-stone-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
              </svg>
            </div>


            {/* CTA Button - links to organizer's registration */}
            {isPastEvent ? (
              <div className="space-y-3">
                <div className={`w-full py-4 rounded-xl text-base font-semibold text-center ${isArchivedEvent
                  ? 'bg-stone-800 text-stone-500 cursor-not-allowed'
                  : 'bg-stone-700 text-stone-400 cursor-not-allowed'
                  }`}>
                  {t('eventEnded') || 'Event beendet'}
                </div>
                {isArchivedEvent && (
                  <p className="text-center text-stone-600 text-xs">
                    {t('eventArchived')}
                  </p>
                )}
              </div>
            ) : (
              <>
                <a
                  href="#"
                  onClick={(e) => {
                    e.preventDefault();
                    if (window.confirm(t('openingExternalLink'))) {
                      window.open(event.eventUrl || organizer?.website || '#', '_blank');
                    }
                  }}
                  className="w-full py-4 rounded-xl text-base font-semibold bg-amber-500 text-stone-950 hover:bg-amber-400 transition-all text-center block"
                  style={{ boxShadow: '0 0 30px rgba(245, 158, 11, 0.2)' }}
                >
                  {event.mxType === 'mx-track' ? t('showTrack') : event.isFlexibleDate ? t('contactOrganizer') : t('registerNow')} →
                </a>
                <p className="text-center text-stone-600 text-xs mt-2">
                  {t('forwardToOrganizer')}
                </p>
              </>
            )}
          </div>
        </div>
      </div>

      {/* Verfügbare Termine – Skills-Camps with multiple dates */}
      {event.category === 'skills-camps' && liveEventDates && liveEventDates.length > 0 && (() => {
        var localeMap = { de: 'de-DE', en: 'en-US', fr: 'fr-FR', nl: 'nl-NL' };
        var locale = localeMap[language] || 'de-DE';
        var now = new Date();
        var labels = {
          title:     language === 'de' ? 'Verfügbare Termine' : language === 'fr' ? 'Dates disponibles' : language === 'nl' ? 'Beschikbare data' : 'Available Dates',
          available: language === 'de' ? 'Verfügbar'          : language === 'fr' ? 'Disponible'         : language === 'nl' ? 'Beschikbaar'       : 'Available',
          fewLeft:   language === 'de' ? 'Wenige frei'       : language === 'fr' ? 'Quelques places'    : language === 'nl' ? 'Weinig plekken'    : 'Few spots left',
          soldOut:   language === 'de' ? 'Ausgebucht'        : language === 'fr' ? 'Complet'            : language === 'nl' ? 'Volgeboekt'        : 'Sold out',
          past:      language === 'de' ? 'Vergangen'         : language === 'fr' ? 'Passé'             : language === 'nl' ? 'Verleden'          : 'Past',
        };
        return (
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
            <div className="flex items-center gap-2 mb-5">
              <svg className="w-5 h-5 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
              </svg>
              <p className="text-[11px] uppercase tracking-wider text-amber-500/60 font-medium">{labels.title}</p>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
              {liveEventDates.map(function(dateEntry, idx) {
                var startStr = dateEntry.start_date || dateEntry.start;
                var endStr   = dateEntry.end_date   || dateEntry.end   || null;
                var status   = dateEntry.status || null;
                var isPast   = new Date(startStr) < now;
                var dateLabel    = formatDateVerbose(startStr, endStr, locale);
                var weekdayLabel = formatWeekdayRange(startStr, endStr, locale);
                var duration     = calculateDuration(startStr, endStr, t);
                var isSelCard = idx === selectedDateIdx;
                var borderClass  = isPast
                  ? 'border-stone-800/40 opacity-50'
                  : isSelCard
                    ? 'border-amber-500/40 ring-1 ring-amber-500/20'
                    : status === 'sold_out'
                      ? 'border-red-800/40'
                      : 'border-stone-800 hover:border-amber-500/30 cursor-pointer';
                return (
                  <div key={idx} onClick={function() { if (!isPast && status !== 'sold_out') { setSelectedDateIdx(idx); saveEventDateSelection(event.id, idx); } }} className={'bg-stone-900/60 rounded-xl border p-4 transition-colors ' + borderClass}>
                    <div className="flex items-start justify-between gap-2">
                      <div className="min-w-0">
                        <p className="text-white font-medium text-sm leading-snug">{dateLabel}</p>
                        <p className="text-stone-500 text-xs mt-0.5">{weekdayLabel}</p>
                      </div>
                      {isPast ? (
                        <span className="flex-shrink-0 px-2 py-0.5 rounded-full text-[10px] font-medium bg-stone-800 text-stone-600">{labels.past}</span>
                      ) : status === 'sold_out' ? (
                        <span className="flex-shrink-0 px-2 py-0.5 rounded-full text-[10px] font-medium bg-red-500/15 text-red-400">{labels.soldOut}</span>
                      ) : status === 'few_left' ? (
                        <span className="flex-shrink-0 px-2 py-0.5 rounded-full text-[10px] font-medium bg-amber-500/15 text-amber-400">{labels.fewLeft}</span>
                      ) : status === 'available' ? (
                        <span className="flex-shrink-0 px-2 py-0.5 rounded-full text-[10px] font-medium bg-emerald-500/15 text-emerald-400">{labels.available}</span>
                      ) : null}
                    </div>
                    <p className="text-stone-600 text-xs mt-2">{duration}</p>
                  </div>
                );
              })}
            </div>
          </div>
        );
      })()}

      {/* Map Section */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="bg-stone-900 overflow-hidden border border-stone-800/10" style={{ height: '350px', borderRadius: '1.5rem' }}>
          {event.coordinates ? (
            <div className="w-full h-full relative">
              <div ref={detailMapContainerRef} style={{ width: '100%', height: '100%' }} />
              <div className="absolute bottom-3 left-3 z-10">
                <a
                  href={`https://www.google.com/maps?q=${event.coordinates.lat},${event.coordinates.lng}`}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="px-4 py-2 bg-stone-900/90 backdrop-blur-sm text-stone-300 rounded-lg text-sm hover:bg-stone-800 hover:text-white transition-colors border border-stone-700/50 flex items-center gap-2"
                >
                  <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
                  </svg>
                  {t('openInMaps')}
                </a>
              </div>
            </div>
          ) : (
            <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-stone-900 to-stone-800">
              <div className="text-center">
                <div className="w-14 h-14 bg-amber-500/10 rounded-full flex items-center justify-center mx-auto mb-4">
                  <svg className="w-7 h-7 text-amber-500/70" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
                  </svg>
                </div>
                <h3 className="text-base font-medium text-white/70 mb-2">{event.location}</h3>
                <p className="text-stone-500 text-sm">{language === 'de' ? 'Keine Kartenkoordinaten verf\u00fcgbar' : 'Map coordinates not available'}</p>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Similar Events - Marquee Style */}
      {similarEvents.length > 0 && (
        <div className="py-16 overflow-hidden">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mb-6">
            <p className="text-stone-500 text-sm font-medium">
              {t('similarEvents')}
            </p>
          </div>

          {/* Marquee Container */}
          <div className="relative">
            <div className="absolute left-0 top-0 bottom-0 w-24 bg-gradient-to-r from-stone-950 to-transparent z-10 pointer-events-none"></div>
            <div className="absolute right-0 top-0 bottom-0 w-24 bg-gradient-to-l from-stone-950 to-transparent z-10 pointer-events-none"></div>

            <div
              className="flex gap-4 py-2"
              style={{
                animation: 'marquee 25s linear infinite',
                width: 'fit-content',
              }}
            >
              {duplicatedSimilar.map((e, index) => (
                <div
                  key={`${e.id}-${index}`}
                  onClick={() => onViewEvent(e)}
                  className="group relative bg-stone-900 rounded-xl overflow-hidden border border-stone-800 hover:border-amber-500/50 transition-all duration-300 cursor-pointer flex-shrink-0"
                  style={{ width: '280px' }}
                >
                  <div className="h-32 relative overflow-hidden">
                    <img src={e.image} alt={e.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
                    <div className="absolute inset-0 bg-gradient-to-t from-stone-900 via-transparent to-transparent"></div>
                    <div className="absolute top-2 left-2 flex items-center gap-1.5">
                      <DisciplineBadge event={e} size="sm" />
                      {e.isNew && (
                        <span className="px-1.5 py-0.5 bg-emerald-500 text-white text-xs font-bold rounded">{t('new')}</span>
                      )}
                    </div>
                  </div>
                  <div className="p-3">
                    <h4 className="text-white font-medium text-sm truncate">{e.name}</h4>
                    <p className="text-stone-500 text-xs mt-1">{formatDate(e.startDate)}</p>
                    <p className="text-amber-400 font-semibold text-sm mt-2">{e.isFree ? t('freeLabel') : e.price}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Friend Popup */}
      {selectedFriend && (
        <FriendDetailPopup friend={selectedFriend} onClose={() => setSelectedFriend(null)} onViewFriend={onViewFriend} />
      )}

      {/* Organizer Popup */}
      {showOrganizerPopup && <OrganizerPopup />}

      <Footer setCurrentView={setCurrentView} onCategoryClick={onCategoryClick} />
    </div>
  );
}

// ��── PUBLIC PROFILE VIEW ──────────────────────────────────────────────────────
function PublicProfileView({ user, onBack }) {
  const { language } = useTranslation();
  const auth = useAuth();
  const { friends, incomingRequests, loadFriends } = useUserState();
  const [actionLoading, setActionLoading] = useState(false);
  const [done, setDone] = useState(false);

  const status = (() => {
    if (!auth.user) return 'not-logged-in';
    if (auth.user.id === user.id) return 'self';
    if (friends.find(f => f.id === user.id && (!f.status || f.status === 'accepted'))) return 'accepted';
    if (friends.find(f => f.id === user.id && f.status === 'pending')) return 'pending-outgoing';
    if (incomingRequests.find(r => r.id === user.id)) return 'pending-incoming';
    return 'none';
  })();

  const t = (key) => ({ de: { sendRequest: 'Freund hinzufügen', requestSent: 'Anfrage gesendet', alreadyFriends: 'Bereits befreundet', accept: 'Annehmen', back: 'Zurück' }, en: { sendRequest: 'Add Friend', requestSent: 'Request sent', alreadyFriends: 'Already friends', accept: 'Accept', back: 'Back' } })[language]?.[key] || key;

  const handleAction = async () => {
    if (!auth.user) return;
    setActionLoading(true);
    try {
      if (status === 'none') await sendFriendRequest(auth.user.id, user.id);
      else if (status === 'pending-incoming') await acceptFriendRequest(auth.user.id, user.id);
      await loadFriends();
      setDone(true);
    } catch (e) { console.error(e); }
    finally { setActionLoading(false); }
  };

  return (
    <div className="min-h-screen bg-stone-950 pt-24 pb-16">
      <div className="max-w-2xl mx-auto px-4">
        <button onClick={onBack} className="flex items-center gap-2 text-stone-400 hover:text-white mb-6 transition-colors">
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
          {t('back')}
        </button>
        <div className="bg-stone-900/50 rounded-2xl border border-stone-800 p-8">
          <div className="flex items-start gap-6">
            <InitialsAvatar name={user.name} avatar={user.avatar} size="2xl" className="border-4 border-stone-700" />
            <div className="flex-1">
              <div className="flex items-center gap-3 flex-wrap">
                <h1 className="text-xl font-bold text-white">{user.name}</h1>
                {status === 'accepted' && <span className="px-2 py-0.5 bg-purple-500/20 text-purple-400 text-xs rounded">Freund</span>}
              </div>
              {user.location && <p className="text-stone-500 text-sm mt-1">{user.location}</p>}
              {user.bio && <p className="text-stone-400 text-sm mt-2 italic">{renderBio(user.bio)}</p>}
            </div>
          </div>

          {auth.user && status !== 'self' && (
            <div className="mt-6 pt-6 border-t border-stone-800">
              {status === 'accepted' && <p className="text-purple-400 text-sm text-center">{t('alreadyFriends')} ✓</p>}
              {status === 'pending-outgoing' && <p className="text-stone-500 text-sm text-center">{t('requestSent')}</p>}
              {(status === 'none' || status === 'pending-incoming') && !done && (
                <button disabled={actionLoading} onClick={handleAction} className="w-full py-3 bg-amber-500 text-stone-950 rounded-xl font-semibold hover:bg-amber-400 disabled:opacity-50">
                  {actionLoading ? '…' : status === 'pending-incoming' ? t('accept') : t('sendRequest')}
                </button>
              )}
              {done && <p className="text-emerald-400 text-sm text-center">Anfrage gesendet ✓</p>}
            </div>
          )}
          {!auth.user && (
            <div className="mt-6 pt-6 border-t border-stone-800 text-center">
              <p className="text-stone-500 text-sm">Melde dich an, um Freundschaftsanfragen zu senden.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// =============================================================================
//  PasswordResetPage - Isoliert vom App-State, verwendet supabase direkt.
//  Wird gerendert wenn Supabase den User nach /reset-password redirectet.
// =============================================================================
export function PasswordResetPage({ onDone }) {
  const detectRecoveryUrl = () => {
    const hash   = new URLSearchParams(window.location.hash.replace(/^#/, ''));
    const search = new URLSearchParams(window.location.search);
    return hash.get('type') === 'recovery' || search.has('code');
  };

  const [phase, setPhase]       = React.useState(() => detectRecoveryUrl() ? 'loading' : 'invalid');
  const [password, setPassword] = React.useState('');
  const [confirm, setConfirm]   = React.useState('');
  const [showPw, setShowPw]     = React.useState(false);
  const [showCf, setShowCf]     = React.useState(false);
  const [error, setError]       = React.useState('');
  const [saving, setSaving]     = React.useState(false);

  const strength = React.useMemo(() => {
    if (!password) return 0;
    let s = 0;
    if (password.length >= 8)          s++;
    if (/[A-Z]/.test(password))        s++;
    if (/[0-9]/.test(password))        s++;
    if (/[^A-Za-z0-9]/.test(password)) s++;
    return s;
  }, [password]);

  const strengthLabel = ['', 'Schwach', 'Mittel', 'Gut', 'Stark'];
  const strengthColor = ['', 'bg-red-500', 'bg-orange-400', 'bg-amber-400', 'bg-green-500'];

  React.useEffect(() => {
    if (phase === 'invalid') return;
    const timeout = setTimeout(() => setPhase(p => p === 'loading' ? 'invalid' : p), 12000);
    const { data: { subscription } } = supabase.auth.onAuthStateChange((event) => {
      if (event === 'PASSWORD_RECOVERY') { clearTimeout(timeout); setPhase('form'); }
    });
    return () => { clearTimeout(timeout); subscription.unsubscribe(); };
  }, []); // eslint-disable-line

  const handleSave = async (e) => {
    e.preventDefault();
    setError('');
    if (password.length < 8)  { setError('Mindestens 8 Zeichen erforderlich.'); return; }
    if (password !== confirm)  { setError('Passwoerter stimmen nicht ueberein.'); return; }
    if (strength < 2)          { setError('Bitte waehle ein staerkeres Passwort.'); return; }
    setSaving(true);
    try {
      const { error: err } = await supabase.auth.updateUser({ password });
      if (err) throw err;
      setPhase('success');
      await supabase.auth.signOut();
    } catch (err) {
      setError(err.message || 'Fehler beim Speichern des Passworts.');
    } finally {
      setSaving(false);
    }
  };

  const EyeOpen = () => (
    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
    </svg>
  );
  const EyeOff = () => (
    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21" />
    </svg>
  );

  const inputCls = 'w-full px-3 py-2.5 bg-stone-800 border border-stone-700 rounded-xl text-white text-sm placeholder-stone-600 focus:outline-none focus:border-amber-500/50 focus:ring-1 focus:ring-amber-500/20 transition-colors';

  return (
    <div className="min-h-screen bg-stone-950 flex items-center justify-center p-4">
      <div className="absolute top-6 left-1/2 -translate-x-1/2">
        <span className="text-amber-500 font-bold text-xl tracking-tight">TrailHub</span>
      </div>
      <div className="bg-stone-900 border border-stone-800 rounded-2xl p-8 max-w-sm w-full shadow-2xl mt-12">

        {phase === 'loading' && (
          <div className="text-center py-4">
            <div className="w-10 h-10 border-2 border-amber-500/30 border-t-amber-500 rounded-full animate-spin mx-auto mb-4" />
            <p className="text-stone-400 text-sm">Link wird geprueft...</p>
          </div>
        )}

        {phase === 'invalid' && (
          <div className="text-center">
            <div className="w-12 h-12 bg-red-500/15 rounded-full flex items-center justify-center mx-auto mb-4">
              <svg className="w-6 h-6 text-red-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <h2 className="text-white font-semibold text-lg mb-2">Link ungueltig oder abgelaufen</h2>
            <p className="text-stone-400 text-sm mb-6">Bitte fordere einen neuen Passwort-Reset-Link an.</p>
            <button onClick={onDone} className="w-full py-2.5 bg-stone-800 text-stone-300 rounded-xl text-sm font-medium hover:bg-stone-700 transition-colors">
              Zurueck zum Login
            </button>
          </div>
        )}

        {phase === 'form' && (
          <>
            <div className="w-12 h-12 bg-amber-500/15 rounded-full flex items-center justify-center mx-auto mb-5">
              <svg className="w-6 h-6 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1 0 01.293-.707l5.964-5.964A6 6 0 1121 9z" />
              </svg>
            </div>
            <h2 className="text-white font-semibold text-lg text-center mb-1">Neues Passwort festlegen</h2>
            <p className="text-stone-500 text-xs text-center mb-6">Mindestens 8 Zeichen. Gross-/Kleinbuchstaben und Zahlen empfohlen.</p>
            {error && (
              <div className="mb-4 px-3 py-2.5 bg-red-500/10 border border-red-500/20 rounded-xl text-red-400 text-sm">{error}</div>
            )}
            <form onSubmit={handleSave} className="space-y-4">
              <div>
                <label className="block text-stone-400 text-xs mb-1.5">Neues Passwort</label>
                <div className="relative">
                  <input
                    type={showPw ? 'text' : 'password'}
                    value={password}
                    onChange={e => setPassword(e.target.value)}
                    required
                    placeholder="Mindestens 8 Zeichen"
                    className={inputCls}
                  />
                  <button type="button" onClick={() => setShowPw(v => !v)} className="absolute right-3 top-1/2 -translate-y-1/2 text-stone-500 hover:text-stone-300 transition-colors">
                    {showPw ? <EyeOff /> : <EyeOpen />}
                  </button>
                </div>
                {password.length > 0 && (
                  <div className="mt-2">
                    <div className="flex gap-1 mb-1">
                      {[1,2,3,4].map(i => (
                        <div key={i} className={`h-1 flex-1 rounded-full transition-colors ${i <= strength ? strengthColor[strength] : 'bg-stone-700'}`} />
                      ))}
                    </div>
                    <p className={`text-[10px] ${strength <= 1 ? 'text-red-400' : strength === 2 ? 'text-orange-400' : strength === 3 ? 'text-amber-400' : 'text-green-400'}`}>
                      {strengthLabel[strength]}
                    </p>
                  </div>
                )}
              </div>
              <div>
                <label className="block text-stone-400 text-xs mb-1.5">Passwort bestaetigen</label>
                <div className="relative">
                  <input
                    type={showCf ? 'text' : 'password'}
                    value={confirm}
                    onChange={e => setConfirm(e.target.value)}
                    required
                    placeholder="Passwort wiederholen"
                    className={`${inputCls} ${confirm && confirm !== password ? 'border-red-500/40' : ''}`}
                  />
                  <button type="button" onClick={() => setShowCf(v => !v)} className="absolute right-3 top-1/2 -translate-y-1/2 text-stone-500 hover:text-stone-300 transition-colors">
                    {showCf ? <EyeOff /> : <EyeOpen />}
                  </button>
                </div>
                {confirm && confirm !== password && (
                  <p className="text-red-400 text-[10px] mt-1">Passwoerter stimmen nicht ueberein</p>
                )}
              </div>
              <button
                type="submit"
                disabled={saving}
                className="w-full py-3 bg-amber-500 text-stone-950 rounded-xl font-semibold hover:bg-amber-400 transition-colors disabled:opacity-50 flex items-center justify-center gap-2 mt-2"
              >
                {saving && (
                  <svg className="w-4 h-4 animate-spin" viewBox="0 0 24 24" fill="none">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                  </svg>
                )}
                {saving ? 'Wird gespeichert...' : 'Passwort speichern'}
              </button>
              <button type="button" onClick={onDone} className="w-full py-2 text-stone-600 hover:text-stone-400 text-xs transition-colors">
                Abbrechen - Zum Login
              </button>
            </form>
          </>
        )}

        {phase === 'success' && (
          <div className="text-center">
            <div className="w-12 h-12 bg-green-500/15 rounded-full flex items-center justify-center mx-auto mb-4">
              <svg className="w-6 h-6 text-green-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
              </svg>
            </div>
            <h2 className="text-white font-semibold text-lg mb-2">Passwort erfolgreich geaendert!</h2>
            <p className="text-stone-400 text-sm mb-6">Melde dich jetzt mit deinem neuen Passwort an.</p>
            <button onClick={onDone} className="w-full py-3 bg-amber-500 text-stone-950 rounded-xl font-semibold hover:bg-amber-400 transition-colors">
              Zum Login
            </button>
          </div>
        )}

      </div>
    </div>
  );
}

// ─── URL ROUTING HELPERS ──────────────────────────────────────────────────────
function parsePathname(pathname) {
  const parts = pathname.replace(/^\//, '').split('/').filter(Boolean);
  const [seg0, seg1, seg2] = parts;
  if (!seg0)                                           return { view: 'landing' };
  if (seg0 === 'events')                               return { view: 'events', category: seg1 || null };
  if (seg0 === 'event' && seg1)                        return { view: 'event-detail', eventId: seg1 };
  if (seg0 === 'map')                                  return { view: 'map' };
  if (seg0 === 'profile' && seg1 === 'friend' && seg2) return { view: 'friend-profile', friendId: seg2 };
  if (seg0 === 'profile' && seg1)                      return { view: 'public-profile', userId: seg1 };
  if (seg0 === 'profile')                              return { view: 'profile' };
  if (seg0 === 'reset-password')                       return { view: 'reset-password' };
  return { view: 'landing' };
}

function buildUrl(view, event, category, publicUserId, friendId) {
  if (view === 'event-detail' && event)              return `/event/${event.id}`;
  if (view === 'events' && category)                 return `/events/${category}`;
  if (view === 'events')                             return '/events';
  if (view === 'map')                                return '/map';
  if (view === 'public-profile' && publicUserId)     return `/profile/${publicUserId}`;
  if (view === 'friend-profile' && friendId)         return `/profile/friend/${friendId}`;
  if (view === 'profile')                            return '/profile';
  return '/';
}

// Main App
export default function OffroadEventsApp() {
  const auth = useAuth();
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [renderTick, _forceRender] = useReducer(x => x + 1, 0);

  // Deep-link: hold the eventId from the URL until events are loaded
  const pendingEventIdRef = useRef(null);
  const urlInitialized = useRef(false);
  const isPopstateNavRef = useRef(false);

  useEffect(() => {
    if (!isSupabaseConfigured()) return;
    fetchOrganizers()
      .then(rows => {
        if (rows?.length > 0) {
          const merged = { ...organizers };
          rows.forEach(r => {
            merged[r.id] = {
              id:            r.id,
              name:          r.name,
              logo:          r.logo          ?? null,
              logoBgColor:   r.logo_bg_color ?? null,
              verified:      r.verified      ?? false,
              since:         r.since         ?? null,
              eventsHosted:  r.events_hosted ?? 0,
              rating:        r.rating        ?? 0,
              specialties:   r.specialties   ?? [],
              website:       r.website       ?? null,
              description:   r.description   ?? '',
            };
          });
          organizers = merged;
          _forceRender();
        }
      })
      .catch(err => console.error('[TrailHub] Organizers fetch error:', err));

    fetchEvents()
      .then(rows => {
        if (!rows || rows.length === 0) return;
              mockEvents = rows.map(r => ({
          id:               r.id,
          name:             r.name,
          category:         r.category,
          subcategory:      r.subcategory       ?? null,
          startDate:        r.start_date,
          endDate:          r.end_date           ?? null,
          location:         r.location,
          coordinates:      (() => {
            const c = r.coordinates;
            if (!c) return null;
            if (c.lat != null && c.lng != null) return c;
            // Normalize legacy {latitude, longitude} format stored in DB
            if (c.latitude != null && c.longitude != null) return { lat: c.latitude, lng: c.longitude };
            return null;
          })(),
          price:            r.price              ?? null,
          priceValue:       r.price_value        ?? null,
          isFree:           r.is_free            ?? false,
          image:            r.image              ?? null,
          status:           r.status             ?? 'upcoming',
          difficulty:       r.difficulty         ?? null,
          beginnerFriendly: r.beginner_friendly  ?? false,
          organizerId:      r.organizer_id        ?? null,
          registeredFriends: Array.isArray(r.registered_friends) ? r.registered_friends : [],
          rallyeRegion:     r.rallye_region       ?? null,
          tripType:         r.trip_type           ?? null,
          skillLevel:       r.skill_level         ?? null,
          mxType:           r.mx_type             ?? null,
          bikeType:         r.bike_type           ?? null,
          groupSize:        r.group_size           ?? null,
          level:            r.level               ?? null,
          isNew:            r.is_new              ?? false,
          hasChanges:       r.has_changes         ?? false,
          changeDetails:    r.change_details      ?? null,
          eventUrl:              r.event_url              ?? null,
          aiSummaryDe:           r.ai_summary_de          ?? null,
          aiSummaryEn:           r.ai_summary_en          ?? null,
          aiSummaryFr:           r.ai_summary_fr          ?? null,
          aiSummaryNl:           r.ai_summary_nl          ?? null,
          aiSummaryUpdatedAt:    r.ai_summary_updated_at  ?? null,
          eventDates:            r.event_dates            ?? null,
          festivalType:          r.festival_type          ?? null,
          isFeatured:            r.is_featured            ?? false,
          isFlexibleDate:        r.is_flexible_date       ?? false,
          bookingType:           r.booking_type           ?? 'fixed',
          flexibleDateInfo:      r.flexible_date_info     ?? null,
          organizerSnap:         r.organizers ? {
            id:           r.organizers.id,
            name:         r.organizers.name,
            logo:         r.organizers.logo          ?? null,
            logoBgColor:  r.organizers.logo_bg_color ?? null,
            verified:     r.organizers.verified      ?? false,
            description:  r.organizers.description   ?? '',
            website:      r.organizers.website       ?? null,
            since:        r.organizers.since         ?? null,
            eventsHosted: r.organizers.events_hosted ?? 0,
            rating:       r.organizers.rating        ?? 0,
            specialties:  r.organizers.specialties   ?? [],
          } : null,
        }));
        _forceRender();
      })
      .catch(err => console.error('[TrailHub] Supabase fetch error:', err));
  }, []);

  const pendingPublicUserIdRef = useRef(null);
  const [currentView, setCurrentView] = useState(() => {
    const { view, eventId, userId } = parsePathname(window.location.pathname);
    if (view === 'event-detail' && eventId) {
      pendingEventIdRef.current = eventId;
      return 'events';
    }
    if (view === 'public-profile' && userId) {
      pendingPublicUserIdRef.current = userId;
      return 'events'; // temporary, resolves after mount
    }
    return view;
  });
  const [selectedPublicUser, setSelectedPublicUser] = useState(null);
  const isLoggedIn = !!auth.user;
  const [selectedEvent, setSelectedEvent] = useState(null);
  const [selectedFriend, setSelectedFriend] = useState(null);
  const [showLoginPrompt, setShowLoginPrompt] = useState(false);
  const [language, setLanguageState] = useState(
    () => localStorage.getItem(LANG_STORAGE_KEY) || 'en'
  );

  // Wrapper: persists language to localStorage + Supabase profile (if logged in)
  const handleSetLanguage = (lang) => {
    setLanguageState(lang);
    localStorage.setItem(LANG_STORAGE_KEY, lang);
    if (auth.user) {
      auth.updateProfile({ preferred_language: lang }).catch(e =>
        console.error('[TrailHub] save preferred_language:', e)
      );
    }
  };
  const [selectedCategory, setSelectedCategory] = useState(() => {
    const { category } = parsePathname(window.location.pathname);
    return category || null;
  });
  const [navigationOrigin, setNavigationOrigin] = useState(null);

  // NEW: Navigation type tracking for POP vs PUSH detection
  const [navigationType, setNavigationType] = useState('PUSH');

  // NEW: User preferred discipline (persisted in real app)
  const [userPreferredDiscipline, setUserPreferredDiscipline] = useState('none');

  // Global user profile data - single source of truth
  const [userProfile, setUserProfile] = useState({
    name: '',
    avatar: '',
    location: '',
    bio: '',
    bike: '',
  });

  // Dashboard state tracking for scroll restoration
  const dashboardStateRef = useRef({ scrollPosition: 0 });
  const [dashboardActiveTab, setDashboardActiveTab] = useState('events');

  // ─── URL ROUTING EFFECTS ──────────────────────────────────────────────────

  // 0) Resolve deep-link /profile/:userId on mount
  useEffect(() => {
    if (pendingPublicUserIdRef.current) {
      const uid = pendingPublicUserIdRef.current;
      pendingPublicUserIdRef.current = null;
      fetchUserById(uid).then(user => {
        if (user) { setSelectedPublicUser(user); setCurrentView('public-profile'); }
      }).catch(() => {});
    }
  }, []); // eslint-disable-line

  // 1) Resolve deep-link /event/:id once events are loaded from Supabase
  useEffect(() => {
    if (pendingEventIdRef.current && mockEvents.length > 0) {
      const targetId = String(pendingEventIdRef.current);
      const event = mockEvents.find(e => String(e.id) === targetId);
      pendingEventIdRef.current = null;
      if (event) {
        setSelectedEvent(event);
        setCurrentView('event-detail');
        setNavigationOrigin('events');
      }
    }
  }, [renderTick]); // eslint-disable-line

  // 2) Browser back/forward → restore view from URL
  useEffect(() => {
    const onPopstate = () => {
      const { view, eventId, category, userId, friendId } = parsePathname(window.location.pathname);
      isPopstateNavRef.current = true;
      if (view === 'event-detail' && eventId) {
        const event = mockEvents.find(e => String(e.id) === String(eventId));
        if (event) { setSelectedEvent(event); setCurrentView('event-detail'); setNavigationOrigin('events'); }
        else setCurrentView('events');
      } else if (view === 'events') {
        setSelectedCategory(category || null);
        setCurrentView('events');
      } else if (view === 'friend-profile' && friendId) {
        // Restore friend profile from URL — look up the friend in current friends list,
        // fall back to fetching by ID if not yet loaded.
        fetchUserById(friendId)
          .then(u => { if (u) { setSelectedFriend(u); setCurrentView('friend-profile'); } else setCurrentView('profile'); })
          .catch(() => setCurrentView('profile'));
      } else if (view === 'public-profile' && userId) {
        fetchUserById(userId).then(u => { if (u) { setSelectedPublicUser(u); setCurrentView('public-profile'); } }).catch(() => {});
      } else {
        setCurrentView(view || 'landing');
      }
      window.scrollTo(0, 0);
    };
    window.addEventListener('popstate', onPopstate);
    return () => window.removeEventListener('popstate', onPopstate);
  }, []); // eslint-disable-line

  // 3) State → URL: push a new history entry on every navigation
  useEffect(() => {
    if (!urlInitialized.current) {
      urlInitialized.current = true;
      return; // keep the original URL on first render
    }
    if (isPopstateNavRef.current) {
      isPopstateNavRef.current = false;
      return; // URL is already correct after popstate
    }
    window.history.pushState({}, '', buildUrl(currentView, selectedEvent, selectedCategory, selectedPublicUser?.id, selectedFriend?.id));
  }, [currentView, selectedEvent, selectedCategory, selectedPublicUser]); // eslint-disable-line

  // User state for registrations, favorites, and per-event date selections
  const [registeredEventIds, setRegisteredEventIds] = useState([]);
  const [favoriteEventIds, setFavoriteEventIds] = useState([]);
  const [eventDateSelections, setEventDateSelections] = useState({});

  // Friends state
  const [friends, setFriends] = useState([]);
  const [incomingRequests, setIncomingRequests] = useState([]);
  const [friendsError, setFriendsError] = useState(null);

  const loadFriends = useCallback(async () => {
    if (!auth.user) return;
    setFriendsError(null);
    try {
      const [f, inc] = await Promise.all([
        fetchFriendsWithStatus(auth.user.id),
        fetchIncomingRequests(auth.user.id),
      ]);
      setFriends(f);
      setIncomingRequests(inc);
    } catch (e) {
      console.error('[TrailHub] loadFriends:', e);
      setFriendsError(e?.message || 'Freundesliste konnte nicht geladen werden');
    }
  }, [auth.user?.id]); // eslint-disable-line

  // Compute which accepted friends are registered at each event (respecting privacy)
  const friendsPerEvent = useMemo(() => {
    const map = new Map();
    friends.filter(f => !f.status || f.status === 'accepted').forEach(friend => {
      const visibility = friend.privacy_registration_visibility ?? 'friends';
      if (visibility === 'nobody') return;
      if (friend.they_hide_from_me) return; // friend has hidden their events from me
      (friend.registered_event_ids ?? []).forEach(eventId => {
        if (!map.has(eventId)) map.set(eventId, []);
        map.get(eventId).push(friend);
      });
    });
    return map;
  }, [friends]);

  useEffect(() => {
    if (auth.user) loadFriends();
    else { setFriends([]); setIncomingRequests([]); }
  }, [auth.user?.id]); // eslint-disable-line

  // ─── REALTIME SUBSCRIPTIONS ──────────────────────────────────��────────────
  // Subscribes to friends + users table changes so the UI updates live
  // without requiring a page reload.
  useEffect(() => {
    if (!auth.user) return;
    const userId = auth.user.id;

    // Channel 1: friends table — catches incoming requests & status changes.
    // Two filters needed (Supabase doesn't support OR in one .on() call):
    // • friend_id = me  → someone sent me a request or accepted mine
    // • user_id = me    → my outgoing rows changed (e.g. accepted by peer)
    const friendsChannel = supabase
      .channel(`rt-friends:${userId}`)
      .on('postgres_changes', {
        event: '*', schema: 'public', table: 'friends',
        filter: `friend_id=eq.${userId}`,
      }, () => { loadFriends(); })
      .on('postgres_changes', {
        event: '*', schema: 'public', table: 'friends',
        filter: `user_id=eq.${userId}`,
      }, () => { loadFriends(); })
      .subscribe();

    // Channel 2: users table — catches when a friend's registered_event_ids
    // changes (i.e. they registered/unregistered for an event).
    // We subscribe to ALL user UPDATEs and filter client-side to friends only,
    // because Supabase Realtime can't filter by "id IN (list)".
    const usersChannel = supabase
      .channel(`rt-users:${userId}`)
      .on('postgres_changes', {
        event: 'UPDATE', schema: 'public', table: 'users',
      }, (payload) => {
        // Only react when a friend's row changed — avoids redundant reloads.
        const changedId = payload.new?.id;
        if (!changedId || changedId === userId) return; // own row handled by auth
        setFriends(prev => {
          const isFriend = prev.some(f => f.id === changedId && (!f.status || f.status === 'accepted'));
          if (!isFriend) return prev; // not our friend, ignore
          // Patch the friend's data in-place so friendsPerEvent recomputes immediately.
          return prev.map(f =>
            f.id === changedId
              ? { ...f,
                  registered_event_ids: payload.new.registered_event_ids ?? f.registered_event_ids,
                  privacy_registration_visibility: payload.new.privacy_registration_visibility ?? f.privacy_registration_visibility,
                }
              : f
          );
        });
      })
      .subscribe();

    // Channel 3: Broadcast — direct friendship-removal notification.
    //
    // WHY THIS EXISTS:
    // remove_friendship() is a SECURITY DEFINER function. Its DELETE
    // operations are recorded in the WAL under the *function-owner* role,
    // not the calling user's role. When Supabase Realtime evaluates RLS to
    // decide which subscribers receive the DELETE event, auth.uid() resolves
    // to NULL for that WAL entry — the event is silently dropped for the
    // *removed* user. Their postgres_changes subscription never fires, so
    // their friends state stays stale and the removed friend's avatar keeps
    // showing on event cards.
    //
    // The fix: after the RPC call the *remover's* client sends a Broadcast
    // on the removed user's personal channel. This is guaranteed delivery
    // (unlike postgres_changes) because it bypasses WAL/RLS entirely.
    const notifyChannel = supabase
      .channel(`user-friendship:${userId}`)
      .on('broadcast', { event: 'friendship_removed' }, () => {
        loadFriends();
      })
      .subscribe();

    return () => {
      supabase.removeChannel(friendsChannel);
      supabase.removeChannel(usersChannel);
      supabase.removeChannel(notifyChannel);
    };
  }, [auth.user?.id]); // eslint-disable-line

  // Safety net: re-validate friend list when the user returns to the tab.
  // Handles the case where a friendship was removed while this tab was
  // in the background and the Broadcast/postgres_changes event was missed.
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible' && auth.user) {
        loadFriends();
      }
    };
    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
  }, [auth.user?.id]); // eslint-disable-line

  // Sync profile data from Supabase when auth.profile changes
  useEffect(() => {
    if (auth.profile) {
      setUserProfile(prev => ({
        ...prev,
        name:     auth.profile.name     || prev.name,
        avatar:   auth.profile.avatar   || prev.avatar,
        location: auth.profile.location || prev.location,
        bio:      auth.profile.bio      || prev.bio,
        bike:     auth.profile.bike     || prev.bike,
      }));
      setRegisteredEventIds(auth.profile.registered_event_ids ?? []);
      setFavoriteEventIds(auth.profile.favorite_event_ids ?? []);
      setEventDateSelections(auth.profile.event_date_selections ?? {});
      // Restore saved language preference from profile (cross-device sync)
      if (auth.profile.preferred_language) {
        setLanguageState(auth.profile.preferred_language);
        localStorage.setItem(LANG_STORAGE_KEY, auth.profile.preferred_language);
      }
    } else if (!auth.user) {
      setRegisteredEventIds([]);
      setFavoriteEventIds([]);
      setEventDateSelections({});
    }
  }, [auth.profile, auth.user]);

  const toggleRegistration = async (eventId) => {
    if (!auth.user) { setShowAuthModal(true); return; }
    // Optimistic UI update
    setRegisteredEventIds(prev =>
      prev.includes(eventId) ? prev.filter(id => id !== eventId) : [...prev, eventId]
    );
    try { await auth.toggleRegistration(eventId); } catch (e) { console.error('[TrailHub] toggleRegistration:', e); }
  };

  const toggleFavorite = async (eventId) => {
    if (!auth.user) { setShowAuthModal(true); return; }
    // Optimistic UI update
    setFavoriteEventIds(prev =>
      prev.includes(eventId) ? prev.filter(id => id !== eventId) : [...prev, eventId]
    );
    try { await auth.toggleFavorite(eventId); } catch (e) { console.error('[TrailHub] toggleFavorite:', e); }
  };

  const saveEventDateSelection = async (eventId, dateIdx) => {
    if (!auth.user) return;
    setEventDateSelections(prev => ({ ...prev, [String(eventId)]: dateIdx }));
    try { await auth.saveEventDateSelection(eventId, dateIdx); } catch (e) { console.error('[TrailHub] saveEventDateSelection:', e); }
  };

  const isRegistered = (eventId) => registeredEventIds.includes(eventId);
  const isFavorite = (eventId) => favoriteEventIds.includes(eventId);

  const saveProfile = async (updates) => {
    if (auth.user) {
      await auth.updateProfile(updates);
    }
    setUserProfile(prev => ({ ...prev, ...updates }));
  };

  // Per-friend privacy: whether the current user has hidden their event
  // registrations from a specific friend.
  // Stored in DB (friends.hide_my_events) so the setting is cross-device
  // and visible to the other user's client — localStorage cannot do this.
  const isHiddenFromFriend = (friendId) => {
    const entry = friends.find(f => f.id === friendId);
    return entry?.i_hide_from_them ?? false;
  };

  const toggleHiddenFromFriend = async (friendId) => {
    if (!auth.user) return;
    const entry = friends.find(f => f.id === friendId);
    const currentlyHidden = entry?.i_hide_from_them ?? false;
    const newValue = !currentlyHidden;
    // Optimistic UI update so the toggle feels instant
    setFriends(prev => prev.map(f =>
      f.id === friendId ? { ...f, i_hide_from_them: newValue } : f
    ));
    try {
      await setHideMyEventsFromFriend(auth.user.id, friendId, newValue);
    } catch (e) {
      console.error('[TrailHub] toggleHiddenFromFriend:', e);
      // Rollback optimistic update on failure
      setFriends(prev => prev.map(f =>
        f.id === friendId ? { ...f, i_hide_from_them: currentlyHidden } : f
      ));
    }
  };

  const userStateValue = {
    registeredEventIds,
    favoriteEventIds,
    eventDateSelections,
    saveEventDateSelection,
    toggleRegistration,
    toggleFavorite,
    isRegistered,
    isFavorite,
    userProfile,
    setUserProfile,
    saveProfile,
    toggleHiddenFromFriend,
    isHiddenFromFriend,
    friends,
    incomingRequests,
    loadFriends,
    friendsPerEvent,
    friendsError,
  };

  const handleCategoryClick = (categoryId) => {
    setNavigationType('PUSH'); // Explicit navigation = PUSH
    setSelectedCategory(categoryId);
    setCurrentView('events');
    window.scrollTo(0, 0);
  };

  const handleViewEvent = (event, origin = 'events', currentCategory = null) => {
    if (!isLoggedIn) {
      setShowLoginPrompt(true);
      return;
    }

    // Save scroll position before navigating away
    if (origin === 'profile' || origin === 'friend-profile') {
      dashboardStateRef.current = {
        scrollPosition: window.scrollY,
        origin: origin,
        activeTab: dashboardActiveTab,
      };
    }

    setNavigationType('PUSH'); // Forward navigation = PUSH
    setNavigationOrigin(origin);
    setSelectedEvent(event);
    setCurrentView('event-detail');
    window.scrollTo(0, 0);
  };

  const handleBackFromDetail = () => {
    // CRITICAL: Set POP navigation type BEFORE changing view
    setNavigationType('POP');

    const returnTo = navigationOrigin || 'events';
    const savedState = dashboardStateRef.current;

    setSelectedEvent(null);
    setNavigationOrigin(null);
    if (returnTo === 'profile' && savedState?.activeTab) {
      setDashboardActiveTab(savedState.activeTab);
    }
    setCurrentView(returnTo);

    // Restore scroll position for profile/dashboard views
    if ((returnTo === 'profile' || returnTo === 'friend-profile') && savedState?.scrollPosition) {
      requestAnimationFrame(() => {
        window.scrollTo(0, savedState.scrollPosition);
      });
    }
    // NOTE: Scroll restoration for Events view is handled by EventsOverview via Context
  };

  const handleViewFriend = (friend, origin = null) => {
    // Save current scroll position for specific views before changing
    if (currentView === 'profile' || currentView === 'friend-profile') {
      dashboardStateRef.current = { scrollPosition: window.scrollY, activeTab: dashboardActiveTab };
    }

    setNavigationType('PUSH');
    if (origin) {
      setNavigationOrigin(origin);
    } else {
      setNavigationOrigin(currentView);
    }
    setSelectedFriend(friend);
    setCurrentView('friend-profile');
    window.scrollTo(0, 0);
  };

  const handleBackFromFriend = () => {
    setNavigationType('POP');
    const returnTo = navigationOrigin || 'events';
    const savedState = dashboardStateRef.current;

    setSelectedFriend(null);
    setNavigationOrigin(null);
    if (returnTo === 'profile' && savedState?.activeTab) {
      setDashboardActiveTab(savedState.activeTab);
    }
    setCurrentView(returnTo);

    // Restore scroll position for profile/dashboard views
    if ((returnTo === 'profile' || returnTo === 'friend-profile') && savedState?.scrollPosition) {
      requestAnimationFrame(() => {
        window.scrollTo(0, savedState.scrollPosition);
      });
    }
  };

  const handleLogout = async () => {
    await auth.signOut();
    setRegisteredEventIds([]);
    setFavoriteEventIds([]);
    setNavigationType('PUSH');
    setCurrentView('landing');
    window.scrollTo(0, 0);
  };

  // Handler for preferred discipline change from Settings
  const handlePreferredDisciplineChange = (newValue) => {
    setUserPreferredDiscipline(newValue);
  };

  // =========================================================================
  // VIEW SWITCHING HANDLERS - Events <-> Map
  // =========================================================================

  // Ref to store Events view state for restoration
  const eventsViewStateRef = useRef(null);
  const previousViewRef = useRef(null);
  const eventsOverviewRef = useRef(null);

  // Handler for switching from Events to Map
  const handleSwitchToMap = useCallback(() => {
    if (currentView === 'events') {
      // CRITICAL: Save EventsOverview state before leaving
      if (eventsOverviewRef.current?.saveCurrentState) {
        eventsOverviewRef.current.saveCurrentState();
      }
      // Save current scroll position for Events view
      eventsViewStateRef.current = {
        scrollPosition: window.scrollY,
        timestamp: Date.now(),
      };
      previousViewRef.current = 'events';
    }
    setNavigationType('PUSH');
    setCurrentView('map');
    window.scrollTo(0, 0);
  }, [currentView]);

  // Handler for switching from Map to Events
  const handleSwitchToEvents = useCallback(() => {
    if (currentView === 'map' && previousViewRef.current === 'events') {
      // Coming back from Map to Events - use POP navigation
      setNavigationType('POP');
      setCurrentView('events');
      // Scroll restoration is handled by EventsOverview via Context
    } else {
      // Fresh navigation to Events
      setNavigationType('PUSH');
      setCurrentView('events');
      window.scrollTo(0, 0);
    }
    previousViewRef.current = null;
  }, [currentView]);

  // Login Prompt Modal
  const LoginPromptModal = () => (
    <div className="fixed inset-0 bg-black/70 backdrop-blur-sm z-50 flex items-center justify-center p-4" onClick={() => setShowLoginPrompt(false)}>
      <div className="bg-stone-900 rounded-2xl border border-stone-700 p-8 max-w-sm w-full text-center shadow-2xl" onClick={e => e.stopPropagation()}>
        <div className="w-16 h-16 bg-amber-500/20 rounded-full flex items-center justify-center mx-auto mb-4">
          <svg className="w-8 h-8 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
          </svg>
        </div>
        <h3 className="text-xl font-semibold text-white mb-2">{t('loginRequired')}</h3>
        <p className="text-stone-400 text-sm mb-6">{t('loginToSee')}</p>
        <button
          onClick={() => { setShowLoginPrompt(false); setShowAuthModal(true); }}
          className="w-full py-3 bg-amber-500 text-stone-950 rounded-xl font-semibold hover:bg-amber-400 transition-colors"
        >
          {t('loginNow')}
        </button>
        <button
          onClick={() => setShowLoginPrompt(false)}
          className="w-full py-2 text-stone-500 text-sm mt-3 hover:text-stone-300 transition-colors"
        >
          {t('later')}
        </button>
      </div>
    </div>
  );

  // Get translation function
  const t = (key) => translations[language]?.[key] || translations.de[key] || key;

  const content = (
    <div className="min-h-screen bg-stone-950">
      {currentView !== 'event-detail' && currentView !== 'friend-profile' && (
        <Navigation
          currentView={currentView}
          setCurrentView={setCurrentView}
          isLoggedIn={isLoggedIn}
          onShowLogin={() => setShowAuthModal(true)}
          language={language}
          setLanguage={handleSetLanguage}
          onSwitchToMap={handleSwitchToMap}
          onSwitchToEvents={handleSwitchToEvents}
        />
      )}

      {currentView === 'landing' && (
        <>
          <HeroSection
            onExplore={() => { setNavigationType('PUSH'); previousViewRef.current = null; setCurrentView('events'); }}
            onMap={() => { setNavigationType('PUSH'); previousViewRef.current = null; setCurrentView('map'); }}
          />
          <FeaturedEvents
            onViewAll={() => { setNavigationType('PUSH'); previousViewRef.current = null; setCurrentView('events'); }}
            onViewEvent={handleViewEvent}
          />
          <Footer setCurrentView={setCurrentView} onCategoryClick={handleCategoryClick} />
        </>
      )}

      {currentView === 'events' && (
        <>
          <EventsOverview
            ref={eventsOverviewRef}
            isLoggedIn={isLoggedIn}
            onViewEvent={handleViewEvent}
            onViewFriend={handleViewFriend}
            initialCategory={selectedCategory}
            userPreferredDiscipline={userPreferredDiscipline}
          />
          <Footer setCurrentView={setCurrentView} onCategoryClick={handleCategoryClick} />
        </>
      )}

      {currentView === 'event-detail' && selectedEvent && (
        <EventDetailPage
          event={selectedEvent}
          onBack={handleBackFromDetail}
          isLoggedIn={isLoggedIn}
          onViewEvent={handleViewEvent}
          setCurrentView={setCurrentView}
          onViewFriend={handleViewFriend}
          onCategoryClick={handleCategoryClick}
        />
      )}

      {(currentView === 'map' || (currentView === 'event-detail' && navigationOrigin === 'map')) && (
        <div style={{ display: currentView === 'map' ? 'block' : 'none' }}>
          <MapPlaceholder
            isLoggedIn={isLoggedIn}
            onViewEvent={handleViewEvent}
            onLoginRequired={() => setShowLoginPrompt(true)}
          />
          <Footer setCurrentView={setCurrentView} onCategoryClick={handleCategoryClick} />
        </div>
      )}

      {currentView === 'profile' && (
        <>
          <ProfileDashboard
            isLoggedIn={isLoggedIn}
            onViewEvent={handleViewEvent}
            onViewFriend={handleViewFriend}
            onLogout={handleLogout}
            setCurrentView={setCurrentView}
            userPreferredDiscipline={userPreferredDiscipline}
            onPreferredDisciplineChange={handlePreferredDisciplineChange}
            activeTab={dashboardActiveTab}
            onActiveTabChange={setDashboardActiveTab}
          />
          <Footer setCurrentView={setCurrentView} onCategoryClick={handleCategoryClick} />
        </>
      )}

      {currentView === 'friend-profile' && selectedFriend && (
        <>
          <FriendProfileView
            friend={selectedFriend}
            onBack={handleBackFromFriend}
            onViewEvent={handleViewEvent}
            isLoggedIn={isLoggedIn}
          />
          <Footer setCurrentView={setCurrentView} onCategoryClick={handleCategoryClick} />
        </>
      )}

      {currentView === 'public-profile' && selectedPublicUser && (
        <>
          <PublicProfileView
            user={selectedPublicUser}
            onBack={() => { setCurrentView('events'); setSelectedPublicUser(null); window.scrollTo(0, 0); }}
          />
          <Footer setCurrentView={setCurrentView} onCategoryClick={handleCategoryClick} />
        </>
      )}

      {currentView === 'impressum' && (
        <ImpressumPage setCurrentView={setCurrentView} />
      )}

      {currentView === 'datenschutz' && (
        <DatenschutzPage setCurrentView={setCurrentView} />
      )}

      {currentView === 'kontakt' && (
        <KontaktPage setCurrentView={setCurrentView} />
      )}

      {currentView === 'admin' && (
        <EventEditor onClose={() => { setNavigationType('POP'); setCurrentView('events'); }} />
      )}

      {/* Login Prompt Modal */}
      {showLoginPrompt && <LoginPromptModal />}

      {/* Auth Modal (echtes Login / Registrierung) */}
      {showAuthModal && <AuthModal onClose={() => setShowAuthModal(false)} />}

      {/* Passwort-Reset Modal – erscheint automatisch nach Klick auf Reset-Link in E-Mail */}
      {auth.isPasswordRecovery && (
        <PasswordResetModal onDone={async () => {
          // Signout beendet den Recovery-Mode und verhindert automatische Anmeldung
          await auth.signOut();
          setShowAuthModal(true);
        }} />
      )}
    </div>
  );

  return (
    <EventsViewProvider>
      <SharedFiltersProvider>
        <NavigationContext.Provider value={{ navigationType, setNavigationType }}>
          <LanguageContext.Provider value={{ language, t: (key) => translations[language]?.[key] || translations.de[key] || key }}>
            <UserStateContext.Provider value={userStateValue}>
              <AppErrorBoundary>
                {content}
              </AppErrorBoundary>
            </UserStateContext.Provider>
          </LanguageContext.Provider>
        </NavigationContext.Provider>
      </SharedFiltersProvider>
    </EventsViewProvider>
  );
}
